                <label class="form-label fw-bold">Price Range</label>
                <div class="d-flex gap-2 align-items-center">
                    <input type="number" class="form-control form-control-sm" placeholder="Min"
                           @bind="_minPrice" @bind:event="onchange" min="0" step="0.01" />
                    <span>–</span>
                    <input type="number" class="form-control form-control-sm" placeholder="Max"
                           @bind="_maxPrice" @bind:event="onchange" min="0" step="0.01" />
                </div>
            </div>

            <div class="form-check mb-3">
                <input class="form-check-input" type="checkbox" id="inStockOnly"
                       @bind="_inStockOnly" />
                <label class="form-check-label" for="inStockOnly">In Stock Only</label>
            </div>

            <div class="d-flex gap-2">
                <button class="btn btn-primary btn-sm" @onclick="ApplyFiltersAsync">Apply Filters</button>
                <button class="btn btn-outline-secondary btn-sm" @onclick="ClearFiltersAsync">Clear Filters</button>
            </div>
        </aside>

        <!-- Main Content -->
        <main class="catalog-main">
            <!-- Toolbar -->
            <div class="catalog-toolbar d-flex justify-content-between align-items-center mb-3">
                <div class="d-flex align-items-center gap-2">
                    <label class="form-label mb-0 fw-bold" for="sortBy">Sort by:</label>
                    <select class="form-select form-select-sm" id="sortBy" style="width: auto;"
                            @bind="_sortBy" @bind:after="OnSortChangedAsync">
                        <option value="price_asc">Price: Low to High</option>
                        <option value="price_desc">Price: High to Low</option>
                        <option value="name_asc">Name: A–Z</option>
                        <option value="rating_desc">Rating: Highest</option>
                    </select>
                </div>
                <div class="text-muted small">
                    @if (_result is not null && _result.TotalCount > 0)
                    {
                        var first = (_currentPage - 1) * PageSize + 1;
                        var last = Math.Min(_currentPage * PageSize, _result.TotalCount);
                        <span>Showing @first–@last of @_result.TotalCount products</span>
                    }
                </div>
            </div>

            <!-- Content States -->
            @if (_loading)
            {
                <div class="d-flex justify-content-center py-5">
                    <div class="spinner-border text-primary" role="status">
                        <span class="visually-hidden">Loading…</span>
                    </div>
                </div>
            }
            else if (_result is null || _result.Items.Count == 0)
            {
                <div class="text-center py-5">
                    <p class="text-muted fs-5">No products found matching your criteria.</p>
                    <button class="btn btn-outline-primary" @onclick="ClearFiltersAsync">Clear Filters</button>
                </div>
            }
            else
