                           @bind="_minPrice" @bind:event="onchange" min="0" step="0.01" />
                    <span>–</span>
                    <input type="number" class="form-control form-control-sm" placeholder="Max"
                           @bind="_maxPrice" @bind:event="onchange" min="0" step="0.01" />
                </div>
            </div>

            <div class="form-check mb-3">
                <input class="form-check-input" type="checkbox" id="inStockOnly"
                       @bind="_inStockOnly" />
                <label class="form-check-label" for="inStockOnly">In Stock Only</label>
            </div>

            <div class="d-flex gap-2">
                <button class="btn btn-primary btn-sm" @onclick="ApplyFiltersAsync">Apply Filters</button>
                <button class="btn btn-outline-secondary btn-sm" @onclick="ClearFiltersAsync">Clear Filters</button>
            </div>
        </aside>

        <!-- Main Content -->
        <main class="catalog-main">
            <!-- Toolbar -->
            <div class="catalog-toolbar d-flex justify-content-between align-items-center mb-3">
                <div class="d-flex align-items-center gap-2">
                    <label class="form-label mb-0 fw-bold" for="sortBy">Sort by:</label>
                    <select class="form-select form-select-sm" id="sortBy" style="width: auto;"
                            @bind="_sortBy" @bind:after="OnSortChangedAsync">
                        <option value="price_asc">Price: Low to High</option>
                        <option value="price_desc">Price: High to Low</option>
                        <option value="name_asc">Name: A–Z</option>
                        <option value="rating_desc">Rating: Highest</option>
                    </select>
                </div>
                <div class="text-muted small">
                    @if (_result is not null && _result.TotalCount > 0)
                    {
                        var first = (_currentPage - 1) * PageSize + 1;
                        var last = Math.Min(_currentPage * PageSize, _result.TotalCount);
                        <span>Showing @first–@last of @_result.TotalCount products</span>
                    }
                </div>
            </div>

            <!-- Content States -->
            @if (_loading)
            {
                <div class="d-flex justify-content-center py-5">
                    <div class="spinner-border text-primary" role="status">
                        <span class="visually-hidden">Loading…</span>
                    </div>
                </div>
            }
            else if (_result is null || _result.Items.Count == 0)
            {
                <div class="text-center py-5">
                    <p class="text-muted fs-5">No products found matching your criteria.</p>
                    <button class="btn btn-outline-primary" @onclick="ClearFiltersAsync">Clear Filters</button>
                </div>
            }
            else
            {
                <!-- Product Grid -->
                <div class="product-grid">
                    @foreach (var product in _result.Items)
                    {
                        <ProductCard Product="product"
                                     OnProductSelected="HandleProductSelected"
                                     OnAddToCart="HandleAddToCart" />
                    }
                </div>

                <!-- Pagination -->
                @if (_totalPages > 1)
                {
                    <nav aria-label="Product pagination" class="mt-4">
                        <ul class="pagination justify-content-center">
                            <li class="page-item @(_currentPage <= 1 ? "disabled" : "")">
                                <button class="page-link" @onclick="() => GoToPageAsync(_currentPage - 1)"
                                        disabled="@(_currentPage <= 1)">Previous</button>
                            </li>
                            @foreach (var page in GetPageNumbers())
                            {
                                <li class="page-item @(page == _currentPage ? "active" : "")">
                                    <button class="page-link" @onclick="() => GoToPageAsync(page)">@page</button>
                                </li>
                            }
                            <li class="page-item @(_currentPage >= _totalPages ? "disabled" : "")">
                                <button class="page-link" @onclick="() => GoToPageAsync(_currentPage + 1)"
                                        disabled="@(_currentPage >= _totalPages)">Next</button>
                            </li>
                        </ul>
                    </nav>
                }
            }
        </main>
    </div>
}

@code {
    private const int PageSize = 12;

    private List<string>? _categories;
    private HashSet<string> _selectedCategories = new();
    private decimal? _minPrice;
    private decimal? _maxPrice;
    private bool _inStockOnly;
    private string _sortBy = "price_asc";

    private PagedResult<Product>? _result;
    private int _currentPage = 1;
    private int _totalPages;
    private bool _loading = true;
    private string? _error;

    protected override async Task OnInitializedAsync()
    {
        try
        {
            var categoriesTask = ProductService.GetCategoriesAsync();
            var searchTask = SearchAsync();
            await Task.WhenAll(categoriesTask, searchTask);
            _categories = await categoriesTask;
        }
        catch (Exception ex)
        {
            _error = ex.Message;
        }
    }

    private async Task SearchAsync()
    {
        _loading = true;
        _error = null;

        try
        {
            var filter = new ProductFilter(
                Categories: _selectedCategories.Count > 0 ? _selectedCategories.ToList() : null,
                MinPrice: _minPrice,
                MaxPrice: _maxPrice,
                InStockOnly: _inStockOnly
            );

            _result = await ProductService.SearchAsync(filter, _sortBy, _currentPage, PageSize);
            _totalPages = (int)Math.Ceiling((double)_result.TotalCount / PageSize);
        }
        catch (Exception ex)
        {
            _error = ex.Message;
        }
        finally
        {
            _loading = false;
        }
    }

    private void ToggleCategory(string category, bool isChecked)
    {
        if (isChecked)
            _selectedCategories.Add(category);
        else
            _selectedCategories.Remove(category);
    }

    private async Task ApplyFiltersAsync()
    {
        _currentPage = 1;
        await SearchAsync();
    }

    private async Task ClearFiltersAsync()
    {
        _selectedCategories.Clear();
        _minPrice = null;
        _maxPrice = null;
        _inStockOnly = false;
        _currentPage = 1;
        await SearchAsync();
    }

    private async Task OnSortChangedAsync()
    {
        _currentPage = 1;
        await SearchAsync();
    }

    private async Task GoToPageAsync(int page)
    {
        if (page < 1 || page > _totalPages) return;
        _currentPage = page;
        await SearchAsync();
    }

    private async Task RetryAsync()
    {
        _error = null;
        _loading = true;
        await OnInitializedAsync();
    }

    private void HandleProductSelected(Product product)
    {
        // Parent-level navigation hook — extend as needed
    }

    private void HandleAddToCart(Product product)
    {
        // Cart integration hook — extend as needed
    }

    private IEnumerable<int> GetPageNumbers()
    {
        const int maxVisible = 5;
        int start = Math.Max(1, _currentPage - maxVisible / 2);
        int end = Math.Min(_totalPages, start + maxVisible - 1);
        start = Math.Max(1, end - maxVisible + 1);

        for (int i = start; i <= end; i++)
            yield return i;
    }
}

