+    private async Task OnSortChangedAsync()
+    {
+        _currentPage = 1;
+        await SearchAsync();
+    }
+
+    private async Task GoToPageAsync(int page)
+    {
+        if (page < 1 || page > _totalPages) return;
+        _currentPage = page;
+        await SearchAsync();
+    }
+
+    private async Task RetryAsync()
+    {
+        _error = null;
+        _loading = true;
+        await OnInitializedAsync();
+    }
+
+    private void HandleProductSelected(Product product)
+    {
+        // Parent-level navigation hook — extend as needed
+    }
+
+    private void HandleAddToCart(Product product)
+    {
+        // Cart integration hook — extend as needed
+    }
+
+    private IEnumerable<int> GetPageNumbers()
+    {
+        const int maxVisible = 5;
+        int start = Math.Max(1, _currentPage - maxVisible / 2);
+        int end = Math.Min(_totalPages, start + maxVisible - 1);
+        start = Math.Max(1, end - maxVisible + 1);
+
+        for (int i = start; i <= end; i++)
+            yield return i;
+    }
+}
